import { Product } from '@/types'

function slug(name: string): string {
  return name
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '')
}

function desc(name: string): string {
  return `${name} — available now through Signal Cart with nationwide shipping. Fast and discreet delivery across the United States.`
}

