export const products: Product[] = raw.map((p) => ({
  ...p,
  slug: slug(p.name),
  shortDescription: desc(p.name),
  description: desc(p.name),
  wholesalePrice: Math.round(p.price / 1.5 * 100) / 100,
  compareAtPrice: Math.random() > 0.7 ? Math.round(p.price * 1.25 * 100) / 100 : null,
  imageUrl: `/images/products/${slug(p.name)}.jpg`,
}))

export function getProductBySlug(slug: string): Product | undefined {
  return products.find((p) => p.slug === slug)
}

export function getProductsByCategory(categorySlug: string): Product[] {
  return products.filter((p) => p.categorySlug === categorySlug)
}

export function getFeaturedProducts(): Product[] {
  return products.filter((p) => p.featured)
}

export function getBestsellers(): Product[] {
  return products.filter((p) => p.bestseller)
}

export function searchProducts(query: string): Product[] {
  const q = query.toLowerCase()
  return products.filter(
    (p) =>
      p.name.toLowerCase().includes(q) ||
      p.tags.some((t) => t.toLowerCase().includes(q)) ||
      p.categoryName.toLowerCase().includes(q)
  )
}

export function getProductsByPriceRange(min: number, max: number): Product[] {
  return products.filter((p) => p.price >= min && p.price <= max)
}

export function getNewArrivals(): Product[] {
  return products.slice(0, 12)
}
